create table zx_process_results (
    condition_group_code         varchar2(200 byte),
    priority                     number(22, 0),
    result_type_code             varchar2(120 byte),
    tax_status_code              varchar2(120 byte),
    numeric_result               number(22, 0),
    alphanumeric_result          varchar2(600 byte),
    status_result                varchar2(600 byte),
    rate_result                  varchar2(600 byte),
    legal_message_code           varchar2(120 byte),
    min_tax_amt                  number(22, 0),
    max_tax_amt                  number(22, 0),
    min_taxable_basis            number(22, 0),
    max_taxable_basis            number(22, 0),
    min_tax_rate                 number(22, 0),
    max_tax_rate                 number(22, 0),
    enabled_flag                 varchar2(4 byte),
    allow_exemptions_flag        varchar2(4 byte),
    allow_exceptions_flag        varchar2(4 byte),
    record_type_code             varchar2(120 byte),
    creation_date                timestamp(6),
    last_update_date             timestamp(6),
    request_id                   number(22, 0),
    program_app_name             varchar2(200 byte),
    program_name                 varchar2(120 byte),
    condition_set_id             number(22, 0),
    exception_set_id             number(22, 0),
    program_login_id             number(22, 0),
    result_id                    number(22, 0),
    content_owner_id             number(22, 0),
    condition_group_id           number(22, 0),
    tax_rule_id                  number(22, 0),
    created_by                   varchar2(256 byte),
    last_updated_by              varchar2(256 byte),
    last_update_login            varchar2(128 byte),
    result_api                   varchar2(4000 byte),
    object_version_number        number(22, 0),
    tax_point_basis_result       varchar2(120 byte),
    self_assesed_flag            varchar2(4 byte),
    inclusive_tax_flag           varchar2(4 byte),
    tax_rate_thrshld_code        varchar2(120 byte),
    taxable_amt_thrshld_code     varchar2(120 byte),
    tax_amt_thrshld_code         varchar2(120 byte),
    taxable_basis_formula_result varchar2(120 byte)
);


